import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { Card, Button } from 'react-bootstrap';
// Importamos el componente de Rating que ya existe en components/
import Rating from './Rating'; 
import { CartContext } from '../context/CartContext'; 
import { ToastContext } from '../context/ToastContext'; // Para feedback visual

const Product = ({ product }) => {
  const { addToCart } = useContext(CartContext);
  const { showToast } = useContext(ToastContext);

  const isOffer = product.isOffer || product.discountPercentage > 0;

  // Manejador para añadir al carrito
  const addToCartHandler = () => {
    const itemToAdd = {
      product: product.id || product._id, 
      name: product.name,
      price: product.price,
      image: product.image || product.media?.[0]?.url, 
      qty: 1, // Añadimos 1 unidad por defecto
    };
    
    addToCart(itemToAdd);
    showToast(itemToAdd); // Mostrar toast con los detalles del producto añadido
  };

  return (
    // Estilo flotante de la tarjeta: h-full para igualar alturas en el grid
    <Card 
      className="my-3 p-3 rounded-xl border-0 h-full flex flex-col transition-all duration-300 hover:shadow-2xl hover:-translate-y-1"
      style={{ 
        backgroundColor: 'var(--card-bg-color)',
        boxShadow: '0 8px 25px rgba(0,0,0,0.05)', // Sombra base sutil
        overflow: 'hidden'
      }}
    >
      {isOffer && (
        // Etiqueta de oferta que usa el color de acento
        <div 
          className="absolute top-0 right-0 text-white text-xs font-bold py-1 px-3 rounded-bl-xl z-10"
          style={{ backgroundColor: 'var(--cta-color)', color: 'var(--brand-dark)' }}
        >
          OFERTA!
        </div>
      )}

      {/* Imagen del Producto */}
      <Link to={`/product/${product.sku}`} className="text-decoration-none">
        <div className="overflow-hidden bg-gray-50 p-4 flex items-center justify-center h-[200px] mb-3 relative rounded-lg">
            <Card.Img 
              src={product.image || product.media?.[0]?.url || '/images/sample.jpg'} 
              variant="top" 
              className="object-contain max-h-[160px] transition-transform duration-500 hover:scale-110" 
              alt={product.name}
            />
        </div>
      </Link>

      <Card.Body className="px-1 pb-2 flex flex-col flex-grow">
        {/* Título */}
        <Link to={`/product/${product.sku}`} className="text-decoration-none flex-grow">
          <Card.Title as="div" className="product-title mb-2 h-12">
            <strong className="text-base font-medium text-slate-800 line-clamp-2 hover:text-[#00A56E] transition-colors">
                {product.name}
            </strong>
          </Card.Title>
        </Link>

        {/* Rating */}
        <Card.Text as="div" className="mb-2">
          <Rating 
              value={product.rating || 0} 
              text={`${product.numReviews || 0} reviews`} 
              // Usamos el color de acento para las estrellas
              color={'var(--cta-color)'} 
          />
        </Card.Text>

        {/* Precio y Botón CTA */}
        <div className="d-flex items-center justify-content-between mt-3 gap-2">
            <Card.Text as="h3" className="mb-0 text-xl font-extrabold text-[#0F172A] flex-grow">
              ${(product.price || 0).toFixed(2)}
            </Card.Text>
            
            <Button 
                onClick={addToCartHandler} 
                className="btn-primary rounded-full px-4 py-2 text-sm shadow-md hover:shadow-lg flex items-center justify-center"
                disabled={product.countInStock === 0}
            >
                {product.countInStock === 0 ? 'Sin Stock' : <i className="fas fa-cart-plus"></i>}
            </Button>
        </div>
      </Card.Body>
    </Card>
  );
};

export default Product;
